#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset) {
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[(offset + i) * matrix_dim + (offset + j)];
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx][i] -= shadow[tx][j] * shadow[j][i];
            }
            shadow[tx][i] /= shadow[i][i];
        }

        for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++) {
                shadow[i + 1][tx] -= shadow[i + 1][j] * shadow[j][tx];
            }
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + (offset + j)] = shadow[i][j];
        }
    }
}

static void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int block_id) {
    int i, j;
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            dia[i][j] = m[(offset + i) * matrix_dim + (offset + j)];
            peri_row[i][j] = m[(offset + i) * matrix_dim + (offset + block_id * BLOCK_SIZE + j)];
            peri_col[i][j] = m[(offset + block_id * BLOCK_SIZE + i) * matrix_dim + (offset + j)];
        }
    }

    for (int idx = 0; idx < BLOCK_SIZE; idx++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_row[i][idx] -= dia[i][j] * peri_row[j][idx];
            }
        }
    }

    for (int idx = 0; idx < BLOCK_SIZE; idx++) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_col[idx][i] -= peri_col[idx][j] * dia[j][i];
            }
            peri_col[idx][i] /= dia[i][i];
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + (offset + block_id * BLOCK_SIZE + j)] = peri_row[i][j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + block_id * BLOCK_SIZE + i) * matrix_dim + (offset + j)] = peri_col[i][j];
        }
    }
}

static void lud_internal_block_omp(float *m, int matrix_dim, int offset, int block_x, int block_y) {
    int i, j, k;
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int global_row_id = offset + block_y * BLOCK_SIZE;
    int global_col_id = offset + block_x * BLOCK_SIZE;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_row[i][j] = m[(offset + i) * matrix_dim + (global_col_id + j)];
            peri_col[i][j] = m[(global_row_id + i) * matrix_dim + (offset + j)];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += peri_col[i][k] * peri_row[k][j];
            }
            m[(global_row_id + i) * matrix_dim + (global_col_id + j)] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i = 0;

    omp_set_num_threads(omp_num_threads);

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

        lud_diagonal_omp(m, matrix_dim, i);

        #pragma omp parallel for schedule(static)
        for (int b = 1; b <= blocks; b++) {
            lud_perimeter_block_omp(m, matrix_dim, i, b);
        }

        #pragma omp parallel for collapse(2) schedule(static)
        for (int by = 1; by <= blocks; by++) {
            for (int bx = 1; bx <= blocks; bx++) {
                lud_internal_block_omp(m, matrix_dim, i, bx, by);
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}
